import{_ as r,M as l,p as h,q as a,R as e,t,N as o,a1 as n}from"./framework-822ca1a4.js";const s={},c=e("h1",{id:"每周一词-right",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#每周一词-right","aria-hidden":"true"},"#"),t(" 每周一词-Right")],-1),d=e("p",null,"2023 年 5 月 15 日 15:42:47",-1),g={href:"https://www.bbc.co.uk/learningenglish/chinese/features/english-in-a-minute/ep-230512",target:"_blank",rel:"noopener noreferrer"},u=n('<h2 id="简介" tabindex="-1"><a class="header-anchor" href="#简介" aria-hidden="true">#</a> 简介</h2><p>“Right”是一个高频词，它的用法很多。名词“right”的意思是“右边”。形容词“right”表示“对的”和“右边的”。</p><h2 id="用法总结" tabindex="-1"><a class="header-anchor" href="#用法总结" aria-hidden="true">#</a> 用法总结</h2><ol><li>用形容词“right”表示“对的，正确的”。</li></ol><ul><li>She helped the little boy who was bullied. She did the right thing.</li><li>Well done! Yot got the answer right.</li></ul><ol start="2"><li>用形容词“right”表示“合适的，恰当的”。</li></ol><ul><li>I think Sandra is the right person to run the community project.</li><li>Are you sure you&#39;ar set the over at the right temperature.</li></ul><ol start="3"><li>用形容词“right”表示“右边的，右侧的，向右的”。</li></ol><ul><li>The right side of the picture is brighter.</li><li>His right leg was hurt in the accident.</li></ul><ol start="4"><li>与形容词相对于，名词“right”表示“右边，右侧”。词组“on the right”的意思是在右边。</li></ol><ul><li>To go to the bank, take the third road on the right.</li><li>My manager was setting to my right in the meeting.</li></ul><ol start="5"><li>形容词“right”还可以表示“健康的；（运行）正常的”。</li></ol><ul><li>I don&#39;t feel right. I might be sick.</li><li>This computer isn&#39;t right. I think it has a virus.</li></ul>',13);function _(p,m){const i=l("ExternalLinkIcon");return h(),a("div",null,[c,d,e("p",null,[e("a",g,[t("BBC"),o(i)])]),u])}const b=r(s,[["render",_],["__file","word-right.html.vue"]]);export{b as default};
